+inline std::string toLower(const std::string &s, size_t start, size_t size)
+{
+  std::ostringstream out;
+
+  size_t end=std::min(s.size(), start+size);
+
+  while (start < end)
+  {
+    out << static_cast<char>(std::tolower(s[start++]));
+  }
+
+  return out.str();
+}
+
