+  dlerror(); // clear possible existing error
+
+  // resolve function calls that will only be used privately
+
+  *reinterpret_cast<void**>(&GCInitLib)=dlsym(lib, "GCInitLib");
+  *reinterpret_cast<void**>(&GCCloseLib)=dlsym(lib, "GCCloseLib");
