+namespace
+{
+
+std::vector<std::shared_ptr<System> > slist;
+
+int find(const std::vector<std::shared_ptr<System> > &list, const std::string &filename)
+{
+  for (size_t i=0; i<list.size(); i++)
+  {
+    if (list[i]->getFilename() == filename)
+    {
+      return i;
+    }
+  }
+
+  return -1;
+}
