+void System::open()
+{
+  if (n_open == 0)
+  {
+    if (gentl->TLOpen(&tl) != GenTL::GC_ERR_SUCCESS)
+    {
+      throw GenTLException("System::open()", gentl);
+    }
+  }
+
+  n_open++;
+}
+
+void System::close()
+{
+  if (n_open > 0)
+  {
+    n_open--;
+  }
+
+  if (n_open == 0)
+  {
+    gentl->TLClose(tl);
+    tl=0;
+
+    nodemap=0;
+    cport=0;
+  }
+}
